mapper.select:
SELECT COUNT(*) FROM hm_query.media_flat

    AND folder = #{folder}
    AND mime_type = #{mimeType}
    AND LOWER(original_name) LIKE LOWER(CONCAT('%', #{originalName}, '%'))
    AND (LOWER(original_name) LIKE LOWER(CONCAT('%', #{q}, '%')) OR LOWER(alt_text) LIKE LOWER(CONCAT('%', #{q}, '%')) OR folder LIKE CONCAT('%', #{q}, '%'))

SELECT id, file_key AS "fileKey", original_name AS "originalName", cdn_url AS "cdnUrl", mime_type AS "mimeType", file_size_bytes AS "fileSizeBytes", width, height, alt_text AS "altText", folder, created_at AS "createdAt" FROM hm_query.media_flat
AND folder = #{folder} AND mime_type = #{mimeType} AND LOWER(original_name) LIKE LOWER(CONCAT('%', #{originalName}, '%')) AND (LOWER(original_name) LIKE LOWER(CONCAT('%', #{q}, '%')) OR LOWER(alt_text) LIKE LOWER(CONCAT('%', #{q}, '%')) OR folder LIKE CONCAT('%', #{q}, '%'))
${orderby} ${pagination}
